export type Snapshot<S> = { version: number; state: S };

interface SampleV1 { id: string; collector: string }
interface SampleV2 { id: string; collector: string; collectedAt: string }
interface SampleV3 { id: string; collector: string; collectedAt: string; status: 'collected' | 'catalogued' }

export type CurrentState = SampleV3;
export const CURRENT_VERSION = 3;

function v1Tov2(snap: Snapshot<SampleV1>): Snapshot<SampleV2> {
  return { version: 2, state: { ...snap.state, collectedAt: '1970-01-01T00:00:00Z' } };
}

function v2Tov3(snap: Snapshot<SampleV2>): Snapshot<SampleV3> {
  return { version: 3, state: { ...snap.state, status: 'collected' } };
}

export function upgradeSnapshot(snap: Snapshot<unknown>): Snapshot<CurrentState> {
  let cur = snap as Snapshot<unknown>;
  if (cur.version === 1) cur = v1Tov2(cur as Snapshot<SampleV1>);
  if (cur.version === 2) cur = v2Tov3(cur as Snapshot<SampleV2>);
  if (cur.version !== CURRENT_VERSION) throw new Error(`unknown version ${cur.version}`);
  return cur as Snapshot<CurrentState>;
}
