export type Snapshot<S> = { version: number; state: S };

interface ShotV1 { shotId: string; status: string }
interface ShotV2 { shotId: string; status: string; shotPoint: string }
interface ShotV3 { shotId: string; status: 'scheduled' | 'fired' | 'cancelled'; shotPoint: string; charge: number }

export type CurrentState = ShotV3;
export const CURRENT_VERSION = 3;

function v1Tov2(snap: Snapshot<ShotV1>): Snapshot<ShotV2> {
  return { version: 2, state: { ...snap.state, shotPoint: 'UNKNOWN' } };
}
function v2Tov3(snap: Snapshot<ShotV2>): Snapshot<ShotV3> {
  const status: ShotV3['status'] =
    snap.state.status === 'fired' ? 'fired' :
    snap.state.status === 'cancelled' ? 'cancelled' : 'scheduled';
  return { version: 3, state: { shotId: snap.state.shotId, status, shotPoint: snap.state.shotPoint, charge: 0 } };
}

export function upgradeSnapshot(snap: Snapshot<unknown>): Snapshot<CurrentState> {
  let cur = snap as Snapshot<unknown>;
  if (cur.version === 1) cur = v1Tov2(cur as Snapshot<ShotV1>);
  if (cur.version === 2) cur = v2Tov3(cur as Snapshot<ShotV2>);
  if (cur.version !== CURRENT_VERSION) throw new Error('bad version');
  return cur as Snapshot<CurrentState>;
}
