type PlanEvent =
  | { type: 'PlanDrafted'; planId: string; site: string }
  | { type: 'PlanApproved'; planId: string; by: string };

interface OutboxRow {
  id: string;
  payload: string;
  publishedAt: string | null;
}

interface Txn {
  insertOutbox(row: OutboxRow): Promise<void>;
  appendToStream(
    stream: string,
    events: PlanEvent[],
    opts: { expectedRevision: bigint | 'no_stream' | 'any' },
  ): Promise<void>;
  commit(): Promise<void>;
  rollback(): Promise<void>;
}

interface Conn {
  begin(): Promise<Txn>;
}

// A separate publisher worker polls OutboxRow WHERE publishedAt IS NULL,
// forwards the payload, then marks the row as published.
export async function appendWithOutbox(
  conn: Conn,
  stream: string,
  events: PlanEvent[],
  outboxRows: OutboxRow[],
): Promise<void> {
  const tx = await conn.begin();
  try {
    for (const row of outboxRows) await tx.insertOutbox(row);
    await tx.appendToStream(stream, events, { expectedRevision: 'any' });
    await tx.commit();
  } catch (err) {
    await tx.rollback();
    throw err;
  }
}
