export async function aggregateStream<S, E>(
  stream: AsyncIterable<E>,
  evolve: (state: S, event: E) => S,
  initial: S,
): Promise<S> {
  let state = initial;
  for await (const event of stream) {
    state = evolve(state, event);
  }
  return state;
}

type BondEvent =
  | { type: 'BondPosted'; amount: number }
  | { type: 'BondReleased'; reason: string };

type State = { status: 'posted' | 'released'; amount: number };

function evolve(state: State, event: BondEvent): State {
  switch (event.type) {
    case 'BondPosted':
      return { status: 'posted', amount: event.amount };
    case 'BondReleased':
      return { status: 'released', amount: state.amount };
    default: {
      const _: never = event;
      return _;
    }
  }
}

export async function load(stream: AsyncIterable<BondEvent>): Promise<State> {
  return aggregateStream<State, BondEvent>(stream, evolve, { status: 'posted', amount: 0 });
}
