type ShotEvent =
  | { type: 'ShotScheduled'; shotPoint: string }
  | { type: 'ShotFired'; at: string }
  | { type: 'ShotCancelled'; reason: string };

type State =
  | { status: 'unscheduled' }
  | { status: 'scheduled'; shotPoint: string }
  | { status: 'fired' }
  | { status: 'cancelled' };

const initialState: State = { status: 'unscheduled' };

export function evolve(state: State, event: ShotEvent): State {
  switch (event.type) {
    case 'ShotScheduled':
      return { status: 'scheduled', shotPoint: event.shotPoint };
    case 'ShotFired':
      return { status: 'fired' };
    case 'ShotCancelled':
      return { status: 'cancelled' };
    default: {
      const _: never = event;
      return _;
    }
  }
}

export function aggregate(events: ShotEvent[]): State {
  return events.reduce(evolve, initialState);
}

void aggregate([{ type: 'ShotScheduled', shotPoint: 'SP-5' }]);
